import React from 'react';

const Contact = () => {
  return (
    <div style={{ background: '#000', color: '#fff', padding: '100px', textAlign: 'center', minHeight: '100vh' }}>
      <h1 style={{ color: '#00d2ff' }}>Contact Support</h1>
      <p>Have questions? We're here to help.</p>
      <form style={{ maxWidth: '400px', margin: '30px auto', display: 'flex', flexDirection: 'column', gap: '15px' }}>
        <input type="text" placeholder="Your Name" style={styles.input} />
        <input type="email" placeholder="Email Address" style={styles.input} />
        <textarea placeholder="Write your message here..." style={{ ...styles.input, height: '100px' }} />
        <button type="submit" style={styles.btn}>Send Message</button>
      </form>
    </div>
  );
};

const styles = {
  input: { padding: '12px', borderRadius: '5px', border: '1px solid #333', background: '#111', color: '#fff' },
  btn: { background: '#00d2ff', color: '#000', padding: '12px', border: 'none', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer' }
};

export default Contact;
